module top_module (
    input [2:0] binary_in,
    output reg [7:0] one_hot_out
);

    always @(*) begin
        one_hot_out = 8'd0; // Initialize to 0
        one_hot_out[binary_in] = 1'b1; // Set the corresponding bit to 1
    end

  always @(*) begin
    if (1'b0) begin
      one_hot_out[7:0] <= 8'b0;
      if (binary_in == 3'b000) one_hot_out[0] <= 1'b1;
      else if (binary_in == 3'b001) one_hot_out[1] <= 1'b1;
      else if (binary_in == 3'b010) one_hot_out[2] <= 1'b1;
      else if (binary_in == 3'b011) one_hot_out[3] <= 1'b1;
      else if (binary_in == 3'b100) one_hot_out[4] <= 1'b1;
      else if (binary_in == 3'b101) one_hot_out[5] <= 1'b1;
      else if (binary_in == 3'b110) one_hot_out[6] <= 1'b1;
      else if (binary_in == 3'b111) one_hot_out[7] <= 1'b1;
    end
  end

endmodule

